import Link from "next/link";

/* ══════════════════════════════════════════════════════════════════════════════
   THEME CONSTANTS
   ══════════════════════════════════════════════════════════════════════════════ */
export const C = {
    navy: "#1e2d44",
    burgundy: "#6b2c3b",
    gold: "#c9953a",
    gray400: "#9ca3af",
    gray600: "#4b5563",
    gray700: "#374151",
    gray800: "#1f2937",
    offWhite: "#f9fafb",
};

/* ══════════════════════════════════════════════════════════════════════════════
   ICONS
   ══════════════════════════════════════════════════════════════════════════════ */
const ArrowLeft = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="19" y1="12" x2="5" y2="12" />
        <polyline points="12 19 5 12 12 5" />
    </svg>
);

export const User = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
        <circle cx="12" cy="7" r="4" />
    </svg>
);

export const Calendar = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <rect x="3" y="4" width="18" height="18" rx="2" ry="2" />
        <line x1="16" y1="2" x2="16" y2="6" />
        <line x1="8" y1="2" x2="8" y2="6" />
        <line x1="3" y1="10" x2="21" y2="10" />
    </svg>
);

export const Clock = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10" />
        <polyline points="12 6 12 12 16 14" />
    </svg>
);

/* ══════════════════════════════════════════════════════════════════════════════
   COMPONENTS
   ══════════════════════════════════════════════════════════════════════════════ */

export function BackButton() {
    return (
        <Link href="/articles" style={{
            display: "inline-flex", alignItems: "center", gap: 8,
            textDecoration: "none",
            color: C.gray700, fontSize: "0.92rem", fontWeight: 500,
            padding: "6px 0", transition: "color 0.2s ease",
            fontFamily: "sans-serif",
        }}>
            <ArrowLeft />
            <span>Back to Articles</span>
        </Link>
    );
}

export function CategoryBadge({ children, colorClassName }: { children: React.ReactNode, colorClassName?: string }) {
    // If colorClassName is provided (e.g. from frontmatter), we might use it. 
    // For now, defaulting to burgundy style, but could be dynamic.
    return (
        <span style={{
            display: "inline-block",
            background: C.burgundy, // or use colorClassName if implemented
            color: "#fff",
            fontSize: "0.8rem",
            fontWeight: 600,
            letterSpacing: "0.03em",
            padding: "5px 14px",
            borderRadius: 6,
            fontFamily: "sans-serif",
        }}>
            {children}
        </span>
    );
}

export function MetaItem({ icon: Icon, children }: { icon: React.ComponentType, children: React.ReactNode }) {
    return (
        <div style={{ display: "flex", alignItems: "center", gap: 6, color: C.gray600, fontSize: "0.88rem", fontFamily: "sans-serif" }}>
            <Icon />
            <span>{children}</span>
        </div>
    );
}

export function HeroImage({ src, alt }: { src?: string, alt?: string }) {
    if (src) {
        return (
            <div style={{
                width: "100%",
                maxWidth: 1100,
                margin: "0 auto",
                aspectRatio: "16 / 7.5",
                borderRadius: 16,
                overflow: "hidden",
                position: "relative",
                boxShadow: "0 8px 32px rgba(0,0,0,0.14)",
            }}>
                <img src={src} alt={alt || "Article Hero"} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            </div>
        );
    }

    /* Fallback: Lady Justice statue placeholder */
    return (
        <div style={{
            width: "100%",
            maxWidth: 1100,
            margin: "0 auto",
            aspectRatio: "16 / 7.5",
            borderRadius: 16,
            overflow: "hidden",
            position: "relative",
            background: "linear-gradient(140deg, #8b7355 0%, #6b5545 25%, #4a3f38 50%, #3d3530 75%, #2d2622 100%)",
            boxShadow: "0 8px 32px rgba(0,0,0,0.14)",
        }}>
            {/* subtle vignette */}
            <div style={{ position: "absolute", inset: 0, background: "radial-gradient(ellipse 70% 60% at 55% 45%, transparent 20%, rgba(0,0,0,0.35) 100%)" }} />

            {/* statue silhouette hints (scales + figure) */}
            <div style={{ position: "absolute", top: "18%", right: "38%", width: "14%", height: "48%", opacity: 0.35 }}>
                {/* figure body */}
                <div style={{ position: "absolute", left: "38%", top: "22%", width: "24%", height: "62%", background: "linear-gradient(to bottom, #a89070 0%, #8b7355 100%)", borderRadius: "12px 12px 24px 24px" }} />
                {/* head */}
                <div style={{ position: "absolute", left: "40%", top: "8%", width: "20%", height: "18%", background: "#a89070", borderRadius: "50%" }} />
                {/* raised arm holding scales */}
                <div style={{ position: "absolute", left: "62%", top: "18%", width: "3px", height: "28%", background: "#8b7355", transformOrigin: "top", transform: "rotate(-35deg)" }} />
                {/* scales beam */}
                <div style={{ position: "absolute", right: "-18%", top: "35%", width: "40%", height: "2px", background: "#6b5545" }} />
                {/* left scale */}
                <div style={{ position: "absolute", right: "20%", top: "37%", width: "8px", height: "8px", borderRadius: "50% 50% 0 0", border: "2px solid #6b5545", borderBottom: "none" }} />
                {/* right scale */}
                <div style={{ position: "absolute", right: "-2%", top: "37%", width: "8px", height: "8px", borderRadius: "50% 50% 0 0", border: "2px solid #6b5545", borderBottom: "none" }} />
            </div>

            {/* subtle grain texture */}
            <div style={{
                position: "absolute", inset: 0, opacity: 0.08, pointerEvents: "none",
                backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E")`,
            }} />
        </div>
    );
}

export function PullQuote({ children }: { children: React.ReactNode }) {
    if (!children) return null;
    return (
        <div style={{
            borderLeft: `4px solid ${ C.gold }`,
            paddingLeft: 28,
            margin: "40px 0",
        }}>
            <p style={{
                fontSize: "clamp(1.15rem, 2.4vw, 1.38rem)",
                lineHeight: 1.65,
                fontStyle: "italic",
                color: C.gray700,
                margin: 0,
                fontFamily: "Georgia, 'Times New Roman', serif",
            }}>
                {children}
            </p>
        </div>
    );
}

import { useState } from "react";
import { T, TeamMember } from "./CoreValue";

export function TeamCard({ name, role, bio, hue }: TeamMember) {
    const [hovered, setHovered] = useState(false);
    const initials = name
        .split(" ")
        .filter(Boolean)
        .map((w: any) => w[0])
        .join("")
        .slice(0, 2)
        .toUpperCase();

    return (
        <div
            onMouseEnter={() => setHovered(true)}
            onMouseLeave={() => setHovered(false)}
            className="text-center"
            style={{
                transform: hovered ? "translateY(-4px)" : "translateY(0)",
                transition: "transform 0.3s cubic-bezier(.22,1,.36,1)",
            }}
        >
            {/* avatar */}
            <div
                className="w-full rounded-xl shadow-xl overflow-hidden flex items-center justify-center mb-4"
                style={{
                    aspectRatio: "1",
                    background: `linear-gradient(145deg, hsl(${ hue },45%,62%) 0%, hsl(${ hue + 20 },50%,48%) 100%)`,
                    boxShadow: hovered ? "0 6px 24px rgba(0,0,0,0.15)" : "0 2px 8px rgba(0,0,0,0.08)",
                    transition: "box-shadow 0.3s ease",
                }}
            >
                {/* <span className="text-white font-light" style={{ fontSize: "clamp(1.6rem, 4vw, 2.2rem)", fontFamily: "Georgia, serif", textShadow: "0 1px 6px rgba(0,0,0,0.2)" }}>
                    {initials}
                </span> */}
                <img src="https://scontent.fktm21-1.fna.fbcdn.net/v/t39.30808-6/299914749_1512516582551863_309940420655358093_n.jpg?_nc_cat=109&ccb=1-7&_nc_sid=1d70fc&_nc_eui2=AeEFANQfVjh9nqlK5E23i2xvYwAR_hGGaDJjABH-EYZoMjVOOQoYkfYzOIv_IiJzqQ_G_Je_KLN-qfQGIgwrPyd4&_nc_ohc=yPkRvmyrBXcQ7kNvwFhPjxb&_nc_oc=AdlIXd5GiUIEcmeIxIxDXwU3gBuSkdoh0gpbaRxjydIG5eyxS_mKSAeNaKSZLsKIKiITlcxh9iWCfK8gpG2-0veL&_nc_zt=23&_nc_ht=scontent.fktm21-1.fna&_nc_gid=MyfuUi1wzWOnRpOAsnLGwA&oh=00_Aft0PFtJNMkrZHJvIfhtadsnmZhu_j1gyrsSZcae1SPxuQ&oe=699BD3F0" alt="" className="" />
            </div>

            <h3 className="font-semibold" style={{ color: T.navy, fontSize: "0.95rem", fontFamily: "Georgia, serif" }}>{name}</h3>
            <p className="mt-1 text-xs font-semibold tracking-wide" style={{ color: T.gold, fontFamily: "sans-serif" }}>{role}</p>
            <p className="mt-2 text-sm leading-relaxed italic" style={{ color: T.gray500, fontFamily: "Georgia, serif" }}>{bio}</p>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import BlogCards from "../../Components/BlogCards";

/* ─── Inline SVG Icons ─────────────────────────────────────────────────────── */
const SparklesIcon = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 2l2.09 6.26L20 10l-5.91 1.74L12 18l-2.09-6.26L4 10l5.91-1.74z" />
        <path d="M19 15l1.2 2.8L23 19l-2.8 1.2L19 23l-1.2-2.8L15 19l2.8-1.2z" />
        <path d="M5 2l.8 2L8 5l-2.2.8L5 8l-.8-2.2L2 5l2.2-.8z" />
    </svg>
);
const BookIcon = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20" />
        <path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z" />
    </svg>
);
const ClockIcon = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10" />
        <polyline points="12 6 12 12 16 14" />
    </svg>
);
const ScalesIcon = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22v-7" /><path d="M4 22h16" />
        <path d="M12 2L5 7l7 5 7-5-7-5z" />
        <path d="M5 7l-3 9h6l-3-9z" /><path d="M19 7l-3 9h6l-3-9z" />
    </svg>
);
const ShieldIcon = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
    </svg>
);
const HeartIcon = () => (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
    </svg>
);
const SearchIcon = () => (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
);

/* ─── Data ─────────────────────────────────────────────────────────────────── */
const categories = [
    { id: "all", label: "All", icon: <SparklesIcon /> },
    { id: "systematic-theology", label: "Systematic Theology", icon: <BookIcon /> },
    { id: "biblical-studies", label: "Biblical Studies", icon: <BookIcon /> },
    { id: "church-history", label: "Church History", icon: <ClockIcon /> },
    { id: "ethics", label: "Ethics", icon: <ScalesIcon /> },
    { id: "apologetics", label: "Apologetics", icon: <ShieldIcon /> },
    { id: "spiritual-formation", label: "Spiritual Formation", icon: <HeartIcon /> },
];

interface Post {
    slug: string;
    title: string;
    date: string;
    author: string;
    category: string;
    categoryColor: string;
    image: string;
    readTime: string;
    description: string;
}

export default function ArticlesClient({ posts }: { posts: any[] }) {
    const [active, setActive] = useState("all");
    const [query, setQuery] = useState("");
    const [mounted, setMounted] = useState(false);
    const [focusSearch, setFocus] = useState(false);

    useEffect(() => {
        const t = setTimeout(() => setMounted(true), 60);
        return () => clearTimeout(t);
    }, []);

    /* stagger helper */
    const fadeIn = (delay = 0) => ({
        opacity: mounted ? 1 : 0,
        transform: mounted ? "translateY(0)" : "translateY(14px)",
        transition: `opacity 0.8s ${ delay }s cubic-bezier(0.22,1,.36,1), transform 0.8s ${ delay }s cubic-bezier(0.22,1,.36,1)`,
    });

    const filteredPosts = posts.filter(post => {
        const matchesCategory = active === "all" || (post.category && post.category.toLowerCase().replace(" ", "-") === active);
        const matchesQuery = post.title.toLowerCase().includes(query.toLowerCase()) ||
            (post.description && post.description.toLowerCase().includes(query.toLowerCase()));
        return matchesCategory && matchesQuery;
    });

    return (
        <div style={{ minHeight: "100vh", fontFamily: "'Georgia', 'Times New Roman', serif", background: "#f9fafb" }}>

            {/* ────── HERO ────────────────────────────────────────────────────── */}
            <header style={{
                position: "relative",
                width: "100%",
                minHeight: 400,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "center",
                background: "linear-gradient(148deg, #2c3e5a 0%, #1e2d44 42%, #243548 72%, #2a3f5f 100%)",
                overflow: "hidden",
                padding: "64px 24px",
            }}>
                {/* decorative blobs */}
                <div style={{ position: "absolute", width: 520, height: 520, top: -140, left: -120, borderRadius: "50%", background: "#5a8ab5", filter: "blur(90px)", opacity: 0.12, pointerEvents: "none" }} />
                <div style={{ position: "absolute", width: 380, height: 380, bottom: -90, right: -90, borderRadius: "50%", background: "#4a7499", filter: "blur(80px)", opacity: 0.12, pointerEvents: "none" }} />

                {/* subtle bottom fade */}
                <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 60, background: "linear-gradient(to bottom, transparent, rgba(249,250,251,0.08))", pointerEvents: "none" }} />

                {/* text content */}
                <div style={{ position: "relative", zIndex: 1, textAlign: "center", ...fadeIn(0) }}>
                    <h1 style={{
                        color: "#fff",
                        fontWeight: 300,
                        letterSpacing: "-0.02em",
                        lineHeight: 1.1,
                        fontSize: "clamp(2.8rem, 7vw, 5.4rem)",
                        textShadow: "0 2px 28px rgba(0,0,0,0.22)",
                        margin: 0,
                    }}>All Articles</h1>

                    <p style={{
                        color: "rgba(255,255,255,0.78)",
                        fontSize: "clamp(0.95rem, 2vw, 1.15rem)",
                        lineHeight: 1.65,
                        maxWidth: 560,
                        margin: "18px auto 0",
                    }}>
                        Explore our collection of theological writings, biblical insights, and spiritual reflections.
                    </p>
                </div>
            </header>

            {/* ────── SEARCH + FILTERS ────────────────────────────────────────── */}
            <section style={{ width: "100%", padding: "52px 20px 60px", background: "#fff" }}>
                <div style={{ maxWidth: 880, margin: "0 auto", display: "flex", flexDirection: "column", alignItems: "center", gap: 24 }}>

                    {/* Search bar */}
                    <div style={{ width: "100%", maxWidth: 640, position: "relative", ...fadeIn(0.12) }}>
                        <div style={{ position: "absolute", left: 16, top: "50%", transform: "translateY(-50%)", color: "#9ca3af", pointerEvents: "none", display: "flex", alignItems: "center" }}>
                            <SearchIcon />
                        </div>
                        <input
                            type="text"
                            placeholder="Search articles..."
                            value={query}
                            onChange={e => setQuery(e.target.value)}
                            onFocus={() => setFocus(true)}
                            onBlur={() => setFocus(false)}
                            style={{
                                width: "100%",
                                height: 52,
                                paddingLeft: 44,
                                paddingRight: 20,
                                fontSize: "1rem",
                                fontFamily: "inherit",
                                color: "#374151",
                                background: "#fff",
                                border: `1.5px solid ${ focusSearch ? "#1e2d44" : "#e2e5ea" }`,
                                borderRadius: 999,
                                outline: "none",
                                boxSizing: "border-box",
                                boxShadow: focusSearch
                                    ? "0 2px 18px rgba(30,45,68,0.18)"
                                    : "0 2px 12px rgba(0,0,0,0.065)",
                                transition: "box-shadow 0.25s ease, border-color 0.25s ease",
                            }}
                        />
                    </div>

                    {/* Category pills */}
                    <div style={{
                        display: "flex", flexWrap: "wrap", justifyContent: "center", gap: 12,
                        ...fadeIn(0.24),
                    }}>
                        {categories.map((cat, i) => {
                            const on = active === cat.id;
                            return (
                                <button
                                    key={cat.id}
                                    onClick={() => setActive(cat.id)}
                                    style={{
                                        display: "flex",
                                        alignItems: "center",
                                        gap: 8,
                                        padding: "10px 20px",
                                        borderRadius: 999,
                                        fontSize: "0.91rem",
                                        fontFamily: "inherit",
                                        cursor: "pointer",
                                        background: on ? "#1e2d44" : "#fff",
                                        color: on ? "#fff" : "#374151",
                                        border: `1.5px solid ${ on ? "#1e2d44" : "#e2e5ea" }`,
                                        boxShadow: on ? "0 2px 10px rgba(30,45,68,0.28)" : "0 1px 4px rgba(0,0,0,0.065)",
                                        /* staggered reveal */
                                        opacity: mounted ? 1 : 0,
                                        transform: mounted ? "translateY(0)" : "translateY(8px)",
                                        transition: `opacity 0.7s ${ 0.28 + i * 0.055 }s cubic-bezier(0.22,1,.36,1),
                                    transform 0.7s ${ 0.28 + i * 0.055 }s cubic-bezier(0.22,1,.36,1),
                                    background 0.22s ease, color 0.22s ease,
                                    border-color 0.22s ease, box-shadow 0.22s ease`,
                                    }}
                                    onMouseEnter={e => {
                                        if (!on) {
                                            e.currentTarget.style.borderColor = "#1e2d44";
                                            e.currentTarget.style.boxShadow = "0 2px 8px rgba(30,45,68,0.14)";
                                        }
                                    }}
                                    onMouseLeave={e => {
                                        if (!on) {
                                            e.currentTarget.style.borderColor = "#e2e5ea";
                                            e.currentTarget.style.boxShadow = "0 1px 4px rgba(0,0,0,0.065)";
                                        }
                                    }}
                                >
                                    <span style={{ display: "flex", alignItems: "center", opacity: on ? 1 : 0.6 }}>
                                        {cat.icon}
                                    </span>
                                    {cat.label}
                                </button>
                            );
                        })}
                    </div>
                </div>
            </section>

            {/* blogs... */}
            <section className='py-16 px-6 lg:px-12 bg-white min-h-screen'>
                <BlogCards posts={filteredPosts} />
            </section>
        </div>
    );
}

"use client";

import React from "react";
import { motion, Variants } from "framer-motion";
import Link from "next/link";
import { Book } from "../../lib/books";
import { BookOpen, User, Tag, ArrowRight, ShoppingCart } from "lucide-react";

interface BooksClientProps {
    books: Book[];
}

export default function BooksClient({ books }: BooksClientProps) {
    const containerVariants: Variants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: {
                staggerChildren: 0.1,
            },
        },
    };

    const itemVariants: Variants = {
        hidden: { y: 20, opacity: 0 },
        visible: {
            y: 0,
            opacity: 1,
            transition: {
                type: "spring",
                stiffness: 100,
            },
        },
    };

    return (
        <div className="min-h-screen bg-slate-50 pt-24 pb-12">
            <div className="max-w-7xl mx-auto px-6 lg:px-12">
                {/* Header Section */}
                <div className="mb-12 text-center">
                    <motion.h1
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="text-4xl md:text-5xl font-bold text-slate-900 mb-4"
                        style={{ fontFamily: "'Libre Baskerville', serif" }}
                    >
                        Our Book Collection
                    </motion.h1>
                    <motion.p
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.2 }}
                        className="text-slate-600 max-w-2xl mx-auto text-lg"
                    >
                        Explore our curated selection of theological insights, spiritual guides, and practical wisdom.
                    </motion.p>
                </div>

                {/* Books Grid */}
                <motion.div
                    variants={containerVariants}
                    initial="hidden"
                    animate="visible"
                    className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-4 gap-8"
                >
                    {books.map((book) => (
                        <motion.div
                            key={book.slug}
                            variants={itemVariants}
                            whileHover={{ y: -1 }}
                            className=" overflow-hidden group transition-all duration-300 bg-red-0 md:w-full"
                        >
                            <Link href={`/books/${ book.slug }`}>
                                <div className="relative h-[290px] overflow-hidden">
                                    <img
                                        src={book.image}
                                        alt={book.title}
                                        className="w-auto h-auto object-cover flex m-auto transition-transform duration-500 group-hover:scale-103"
                                    />
